"""ログ行パーサ。"""
import re

LINE_RE = re.compile(r"^(?P<ts>\S+) (?P<level>\w+) (?P<msg>.*)$")


def parse_line(line: str) -> dict | None:
    m = LINE_RE.match(line.strip())
    if not m:
        return None
    return m.groupdict()


def parse_lines(lines: list[str]) -> list[dict]:
    out = []
    for line in lines:
        rec = parse_line(line)
        if rec is not None:
            out.append(rec)
    return out

