import React from "react";

type Todo = { id: number; title: string; done: boolean };

export function TodoList({ todos }: { todos: Todo[] }) {
  return (
    <ul>
      {todos.map((t) => (
        <li key={t.id}>{t.done ? "✓ " : ""}{t.title}</li>
      ))}
    </ul>
  );
}
